/* ================================================
   METI WEBSITE — GLOBAL DESIGN SYSTEM
   ================================================ */

@import url('https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700;800&display=swap');

:root {
    --primary-dark:  #0a1628; /* Deep Navy */
    --primary:       #1e3a5f; /* Royal Blue */
    --primary-light: #2d5f8a; /* Sky Blue */
    --accent:        #00b4d8; /* Teal */
    --accent-glow:   #00cfff; /* Neon Teal */
    --gold:          #f0a500; /* Gold */
    --gold-light:    #ffc947; /* Light Gold */
    --surface:       #f0f4f8; /* Soft White */
    --surface-alt:   #e8edf3; /* Blue Grey */
    --text-dark:     #1a1a2e; /* Near Black */
    --text-muted:    #6b7b8d; /* Muted */

    /* Placement Specific Colors mapped to global */
    --navy: #001f3f;
    --navy-light: #003366;
    --teal: #008080;
    --glass: rgba(255, 255, 255, 0.85);
    --glass-border: rgba(255, 255, 255, 0.3);

    --shadow-premium: 0 15px 40px rgba(0, 0, 0, 0.08);
    --transition-smooth: all 0.4s cubic-bezier(0.4, 0, 0.2, 1);
}

/* ===== GLOBAL RESET ===== */
body {
    font-family: 'Inter', Arial, sans-serif;
    margin: 0;
    padding: 0;
    background-color: #f0f4f8;
    color: #1a1a2e;
    -webkit-font-smoothing: antialiased;
    animation: pageReveal 0.8s ease-out forwards;
}

@keyframes pageReveal {
    from { opacity: 0; transform: translateY(10px); }
    to { opacity: 1; transform: translateY(0); }
}

/* ===== SCROLLBAR ===== */
::-webkit-scrollbar {
    width: 8px;
}
::-webkit-scrollbar-track {
    background: #e8edf3;
}
::-webkit-scrollbar-thumb {
    background: linear-gradient(180deg, #1e3a5f, #00b4d8);
    border-radius: 4px;
}

/* ===== GLOBAL UTILITIES ===== */
.btn, .card, .glass-card, .achievement-card {
    transition: var(--transition-smooth) !important;
}

.text-navy { color: var(--navy) !important; }
.text-teal { color: var(--teal) !important; }

.shadow-premium {
    box-shadow: 0 25px 60px rgba(0, 0, 0, 0.12);
}

.btn-outline-navy {
    border: 2px solid var(--navy);
    color: var(--navy);
    transition: all 0.4s ease;
}
.btn-outline-navy:hover {
    background: var(--navy);
    color: white;
}

.btn-teal {
    background: linear-gradient(135deg, #008080 0%, #006666 100%) !important;
    border: none !important;
    color: white !important;
    transition: all 0.3s ease !important;
    box-shadow: 0 8px 20px rgba(0, 128, 128, 0.25) !important;
}
.btn-teal:hover {
    background: linear-gradient(135deg, #006666 0%, #004d4d 100%) !important;
    transform: translateY(-3px);
    box-shadow: 0 12px 25px rgba(0, 128, 128, 0.4) !important;
}

/* Section Title — Global */
.section-title,
.section-title h2 {
    font-size: 28px;
    font-weight: 700;
    color: #1e3a5f;
    position: relative;
    display: inline-block;
    padding-bottom: 15px;
    margin-bottom: 30px !important;
}
.section-title::after,
.section-title h2::after {
    content: '';
    position: absolute;
    bottom: 0;
    left: 0;
    width: 60px;
    height: 4px;
    background: linear-gradient(90deg, #00b4d8, #f0a500);
    border-radius: 2px;
}

/* ================================================
   TOP BAR
   ================================================ */
.top-bar {
  background: linear-gradient(135deg, #ffffff 0%, #e8edf3 50%, #dce4f0 100%);
  border-bottom: 2px solid transparent;
  border-image: linear-gradient(90deg, #00b4d8, #1e3a5f, #f0a500) 1;
  animation: slideDown 0.8s ease forwards;
}

@keyframes slideDown {
  0% { opacity: 0; transform: translateY(-60px); }
  100% { opacity: 1; transform: translateY(0); }
}



.title-text {
  margin-left: 50px;
  animation: textDrop 1s ease forwards;
}




.language-switch button {
  border: none;
  background: linear-gradient(135deg, #1e3a5f, #2d5f8a);
  color: white;
  padding: 4px 12px;
  margin-left: 5px;
  border-radius: 6px;
  font-size: 12px;
  font-weight: 600;
  cursor: pointer;
  transition: all 0.3s ease;
  letter-spacing: 0.5px;
}
.language-switch button:hover {
  background: linear-gradient(135deg, #00b4d8, #1e3a5f);
  transform: translateY(-2px);
  box-shadow: 0 4px 12px rgba(0, 180, 216, 0.3);
}

/* Date Time */
.datetime {
  font-size: 14px;
  color: #6b7b8d;
  font-weight: 500;
}
#currentDate { display: inline-block; }
#currentTime {
  font-weight: 700;
  color: #1e3a5f;
}

/* Logo */
.logo img {
  width: 120px;
  transition: all 0.4s ease;
  cursor: pointer;
  animation: logoDrop 0.8s ease forwards;
}
.logo img:hover {
  transform: scale(1.08) rotate(-2deg);
  filter: drop-shadow(0 8px 16px rgba(0, 180, 216, 0.25));
}

/* Title */
.title-text h1 {
  font-size: 18px;
  font-weight: 800;
  color: #1e3a5f;
  margin: 0;
  letter-spacing: 0.8px;
  position: relative;
  display: inline-block;
  transition: all 0.3s ease;
}
.title-text h1::after {
  content: "";
  position: absolute;
  width: 0%;
  height: 3px;
  left: 0;
  bottom: -4px;
  background: linear-gradient(90deg, #00b4d8, #f0a500);
  transition: 0.4s ease;
  border-radius: 2px;
}
.title-text h1:hover::after { width: 100%; }
.title-text h1:hover { color: #0a1628; }

/* Subtitle */
.subtitle {
  font-size: 12px;
  color: #6b7b8d;
  margin: 2px 0;
  font-weight: 500;
  transition: all 0.3s ease;
}
.subtitle:hover {
  color: #1a1a2e;
  transform: translateX(4px);
}

/* METI Badge */
.meti {
  font-size: 13px;
  font-weight: 700;
  color: #1e3a5f;
  margin-top: 6px;
  background: linear-gradient(135deg, #e8f4fd, #d0e8f7);
  padding: 5px 14px;
  display: inline-block;
  border-radius: 8px;
  border: 1px solid rgba(0, 180, 216, 0.2);
  transition: all 0.3s ease;
}
.meti:hover {
  background: linear-gradient(135deg, #1e3a5f, #00b4d8);
  color: #fff;
  transform: translateY(-3px);
  box-shadow: 0 8px 20px rgba(0, 180, 216, 0.3);
  border-color: transparent;
}

/* Mobile Top Bar */
@media (max-width: 768px) {
  .logo img { width: 70px; }
  .title-text h1 { font-size: 14px; }
  .subtitle { font-size: 10px; }
  .meti { font-size: 10px; }
  .title-text { margin-left: 15px; }
}

@keyframes logoDrop {
  0% { opacity: 0; transform: translateY(-30px); }
  100% { opacity: 1; transform: translateY(0); }
}
@keyframes textDrop {
  0% { opacity: 0; transform: translateY(-15px); }
  100% { opacity: 1; transform: translateY(0); }
}

/* ================================================
   NAVBAR
   ================================================ */
.nav-container {
  background: linear-gradient(135deg, #0a1628 0%, #1e3a5f 40%, #2d5f8a 100%);
  background-size: 200% 200%;
  animation: navGradient 10s ease infinite;
  box-shadow: 0 4px 20px rgba(10, 22, 40, 0.3);
  border-bottom: 2px solid rgba(0, 180, 216, 0.2);
}

@keyframes navGradient {
  0% { background-position: 0% 50%; }
  50% { background-position: 100% 50%; }
  100% { background-position: 0% 50%; }
}

/* Nav Links */
.nav-container .nav-link {
  color: #e0e8f0 !important;
  font-weight: 500;
  font-size: 14px;
  transition: all 0.3s ease;
  padding: 8px 14px !important;
  border-radius: 6px;
  position: relative;
}
.nav-container .nav-link:hover {
  color: #ffc947 !important;
  background: rgba(255, 255, 255, 0.08);
}
.nav-container .navbar-nav { gap: 4px; }

/* Icon spacing */
.nav-link i, .dropdown-item i {
  margin-right: 6px;
  font-size: 13px;
  opacity: 0.85;
}
.dropdown-item:hover i { opacity: 1; }

/* Dropdown Arrow */
.nav-container .dropdown-toggle::after {
  border-top-color: #e0e8f0;
  transition: 0.3s;
}
.nav-item.dropdown:hover .dropdown-toggle::after {
  transform: rotate(180deg);
  border-top-color: #ffc947;
}

/* Dropdown Menu */
.dropdown-menu {
  border: none;
  border-radius: 10px;
  box-shadow: 0 12px 35px rgba(10, 22, 40, 0.2);
  background: #ffffff;
  padding: 8px;
  overflow: hidden;
}

/* Hover Dropdown (Desktop Only) */
@media (min-width: 992px) {
  .nav-item.dropdown:hover > .dropdown-menu {
    display: block;
    opacity: 1;
    visibility: visible;
    transform: translateY(0);
    pointer-events: auto;
  }
  .nav-item.dropdown .dropdown-menu {
    display: block;
    opacity: 0;
    visibility: hidden;
    transform: translateY(8px);
    transition: all 0.25s ease;
    pointer-events: none;
    margin-top: 0;
  }
}

/* Dropdown Items */
.dropdown-item {
  padding: 10px 16px;
  border-radius: 6px;
  font-size: 14px;
  font-weight: 500;
  color: #1a1a2e;
  transition: all 0.25s ease;
}
.dropdown-item:hover {
  background: linear-gradient(135deg, #1e3a5f, #00b4d8);
  color: #ffffff;
  transform: translateX(4px);
}

/* ================================================
   FOOTER
   ================================================ */
.site-footer {
  background: linear-gradient(180deg, #0a1628 0%, #1e3a5f 100%);
  color: #e0e8f0;
  padding: 70px 20px 20px;
  font-family: 'Inter', sans-serif;
  position: relative;
}

.site-footer::before {
  content: '';
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  height: 3px;
  background: linear-gradient(90deg, #00b4d8, #f0a500, #00b4d8);
}



.footer-section h3 {
  font-size: 18px;
  margin-bottom: 18px;
  font-weight: 700;
  color: #00b4d8;
  letter-spacing: 0.5px;
  position: relative;
  padding-bottom: 10px;
}

.footer-section h3::after {
  content: '';
  position: absolute;
  bottom: 0;
  left: 0;
  width: 30px;
  height: 2px;
  background: #f0a500;
  border-radius: 2px;
}

.footer-section p,
.footer-section li {
  font-size: 14px;
  line-height: 1.9;
  color: #b0c4d8;
}



.footer-section ul li a {
  color: #b0c4d8;
  text-decoration: none;
  transition: all 0.3s ease;
  display: inline-block;
  font-size: 14px;
}

.footer-section ul li a:hover {
  color: #ffc947;
  transform: translateX(5px);
}

/* Footer content icons */
.footer-section p i,
.footer-section li a i {
  margin-right: 8px;
  color: #00b4d8;
  font-size: 13px;
  width: 16px;
  text-align: center;
}

/* Footer Bottom */
.footer-bottom {
  margin-top: 40px;
  text-align: center;
  border-top: 1px solid rgba(255, 255, 255, 0.1);
  padding-top: 25px;
}

.follow-title {
  font-size: 16px;
  font-weight: 600;
  color: #ffc947;
  margin-bottom: 15px;
  letter-spacing: 1px;
  text-transform: uppercase;
}

.footer-bottom p {
  color: #6b7b8d;
  font-size: 13px;
}

.social-links {
  margin-bottom: 20px;
}

.social-links a {
  width: 42px;
  height: 42px;
  margin: 0 10px;
  color: #e0e8f0;
  font-size: 16px;
  background: rgba(255, 255, 255, 0.06);
  border-radius: 50%;
  border: 1px solid rgba(255, 255, 255, 0.1);
  transition: all 0.3s ease;
}

.social-links a:hover {
  color: #0a1628;
  background: #00b4d8;
  border-color: #00b4d8;
  transform: translateY(-3px);
  box-shadow: 0 6px 20px rgba(0, 180, 216, 0.35);
}

/* Responsive Footer */
@media (max-width: 900px) {
  .footer-container {
    flex-direction: column;
    gap: 30px;
    align-items: flex-start;
  }
  .footer-bottom p {
    font-size: 12px;
  }
}
